Javascript.validate:
var value = Services.getValue(this.dataBinding);
var errCode = null;
if (!CaseManUtils.isBlank(value)) 
{
	errCode = CaseManValidationHelper.validatePattern(value, CaseManValidationHelper.NUMERIC_PATTERN, "CaseMan_Reports_Enter_Number");
}
if (errCode == null)
{
	// defect 4926 - should be less than 1, not 0
	if ((value < 1) || (value > 100))
	{
		errCode = ErrorCode.getErrorCode("CaseMan_Reports_PercentageNotInCorrectRange_Msg");
	}
}
return errCode;
